    {EnsureCanView(u);if(!string.IsNullOrWhiteSpace(faena))EnsureFaena(u,faena);var users=await _dbContext.Users.AsNoTracking().Include(x=>x.Roles).ThenInclude(x=>x.Role).Include(x=>x.Faenas).ThenInclude(x=>x.Faena).Where(x=>x.IsActive&&!x.IsLocked).ToArrayAsync(ct);return users.Where(x=>HasRole(x,role)&&(string.IsNullOrWhiteSpace(faena)||HasRole(x,AuthRoles.Admin)||x.Faenas.Any(f=>f.IsActive&&Same(f.Faena.Code,faena)))).Select(x=>new WorkOrderUserLookupResponse(x.Id,x.Username,x.DisplayName,x.Email)).ToArray();}
