    private static (DateTimeOffset? Start,DateTimeOffset? End,decimal Hours) Times(DateOnly d,TimeOnly? start,TimeOnly? end,decimal? h){if(start.HasValue||end.HasValue){if(!start.HasValue||!end.HasValue)throw new DomainException("Debe indicar inicio y término.");var s=new DateTimeOffset(d.ToDateTime(start.Value),TimeSpan.Zero);var e=new DateTimeOffset(d.ToDateTime(end.Value),TimeSpan.Zero);if(e<=s)throw new DomainException("Término debe ser posterior.");return(s,e,Math.Round((decimal)(e-s).TotalHours,2));}if(!h.HasValue||h<=0)throw new DomainException("HH inválidas.");return(null,null,h.Value);}
    private static void EnsureCompletion(WorkOrderEntity o,WorkOrderTaskEntity t){if(t.RequiresLabor&&!o.Labor.Any(x=>x.IsActive&&x.TaskId==t.Id))throw new DomainException("Falta HH.");if(!o.Evidences.Any(x=>x.IsActive&&x.TaskId==t.Id&&x.IsPhoto))throw new DomainException("Falta fotografía.");if(o.Checklist.Any(x=>x.IsActive&&x.TaskId==t.Id&&x.Mandatory&&!x.Completed))throw new DomainException("Falta checklist.");}
    private void Invalidate(WorkOrderEntity o,Guid by,string reason){foreach(var s in o.Signatures.Where(x=>x.IsActive)){s.IsActive=false;s.InvalidatedByUserId=by;s.InvalidatedAtUtc=DateTimeOffset.UtcNow;s.InvalidationReason=reason;}}
    private static WorkOrderTaskStatus Status(WorkOrderTaskEntity x)=>ParseEnum(x.Status.Code,WorkOrderTaskStatus.PendienteAsignacion);private static bool ActiveTask(WorkOrderTaskEntity x)=>x.IsActive&&Status(x)!=WorkOrderTaskStatus.Cancelada;private static Guid Actor(UserAccessContext x)=>Guid.TryParse(x.UserId,out var id)?id:throw new UnauthorizedAccessException("Usuario sin UUID.");private static bool HasRole(AppUserEntity x,string role)=>x.Roles.Any(r=>r.IsActive&&r.Role.IsActive&&Same(r.Role.Code,role));private static bool Has(UserAccessContext x,string p)=>x.Permissions.Contains(p,StringComparer.OrdinalIgnoreCase);private static void Require(UserAccessContext x,string p,string role){if(AnyRole(x,AuthRoles.Admin)||Has(x,p)||AnyRole(x,role))return;throw new UnauthorizedAccessException("Permiso OT requerido.");}private static void EnsureSupervisor(UserAccessContext x,WorkOrderEntity o){if(AnyRole(x,AuthRoles.Admin))return;var actor=Actor(x);if(o.SupervisorUserId==actor&&(AnyRole(x,AuthRoles.MaintenanceSupervisor)||Has(x,AuthPermissions.ManageWorkOrderTasks)))return;throw new UnauthorizedAccessException("Supervisor responsable requerido.");}private static void EnsureManageTechnicians(UserAccessContext x,WorkOrderEntity o)=>EnsureSupervisor(x,o);private static void EnsureTechnician(UserAccessContext x,WorkOrderEntity o){if(AnyRole(x,AuthRoles.Admin))return;var actor=Actor(x);if(o.Technicians.Any(t=>t.IsActive&&t.TechnicianUserId==actor)&&(AnyRole(x,AuthRoles.Technician)||Has(x,AuthPermissions.ExecuteAssignedWorkOrders)))return;throw new UnauthorizedAccessException("Técnico asignado requerido.");}private static void EnsureParticipant(UserAccessContext x,WorkOrderEntity o,Guid id){if(AnyRole(x,AuthRoles.Admin)||(AnyRole(x,AuthRoles.Technician)&&(o.Technicians.Any(t=>t.IsActive&&t.TechnicianUserId==id)||o.Labor.Any(l=>l.IsActive&&l.TechnicianUserId==id))))return;throw new UnauthorizedAccessException("Participante requerido.");}
